import{_ as e,o as l,c as t,ag as i}from"./chunks/framework.DXGyWiRo.js";const o="/images/navi1.png?raw=true",u=JSON.parse('{"title":"1 GO环境配置","description":"","frontmatter":{},"headers":[],"relativePath":"01/0.md","filePath":"01/0.md","lastUpdated":null}'),r={name:"01/0.md"};function n(s,a,_,p,d,c){return l(),t("div",null,[...a[0]||(a[0]=[i('<h1 id="_1-go环境配置" tabindex="-1">1 GO环境配置 <a class="header-anchor" href="#_1-go环境配置" aria-label="Permalink to &quot;1 GO环境配置&quot;">​</a></h1><p>欢迎来到Go的世界，让我们开始探索吧！</p><p>Go是一种新的语言，一种并发的、带垃圾回收的、快速编译的语言。它具有以下特点：</p><ul><li>它可以在一台计算机上用几秒钟的时间编译一个大型的Go程序。</li><li>Go为软件构造提供了一种模型，它使依赖分析更加容易，且避免了大部分C风格include文件与库的开头。</li><li>Go是静态类型的语言，它的类型系统没有层级。因此用户不需要在定义类型之间的关系上花费时间，这样感觉起来比典型的面向对象语言更轻量级。</li><li>Go完全是垃圾回收型的语言，并为并发执行与通信提供了基本的支持。</li><li>按照其设计，Go打算为多核机器上系统软件的构造提供一种方法。</li></ul><p>Go是一种编译型语言，它结合了解释型语言的游刃有余，动态类型语言的开发效率，以及静态类型的安全性。它也打算成为现代的，支持网络与多核计算的语言。要满足这些目标，需要解决一些语言上的问题：一个富有表达能力但轻量级的类型系统，并发与垃圾回收机制，严格的依赖规范等等。这些无法通过库或工具解决好，因此Go也就应运而生了。</p><p>在本章中，我们将讲述Go的安装方法，以及如何配置项目信息。</p><h2 id="目录" tabindex="-1">目录 <a class="header-anchor" href="#目录" aria-label="Permalink to &quot;目录&quot;">​</a></h2><p><img src="'+o+'" alt=""></p><h2 id="links" tabindex="-1">links <a class="header-anchor" href="#links" aria-label="Permalink to &quot;links&quot;">​</a></h2><ul><li><a href="/">目录</a></li><li>下一节: <a href="/01/1.html">安装Go</a></li></ul>',10)])])}const m=e(r,[["render",n]]);export{u as __pageData,m as default};
